import AppRouter from "./routes/AppRouter";
import {useEffect} from 'react';
import {useLocation} from 'react-router-dom';
import {usePaymentAuth} from './routes/ProtectedRoute';

function App() {
    // useAutoLogin();
    const location = useLocation();
    const {setPaymentAuthed} = usePaymentAuth();

    useEffect(() => {
        if (location.pathname !== '/wallet/charge' && location.pathname !== '/wallet/refund' && location.pathname !== '/wallet/accountManagement' && location.pathname !== '/settlement/withdrawal') {
            setPaymentAuthed(false);
        }
    }, [location.pathname, setPaymentAuthed]);
    return (
        <>
            <AppRouter/>
            <div id="modal-root"></div>
        </>
    );
}

export default App;
